import{CursorPage}from"../../../core/pagination.js";import{APIResource}from"../../../core/resource.js";import{path}from"../../../internal/utils/path.js";import{Checkpoints}from"./checkpoints.js";var Jobs=class extends APIResource{constructor(){super(...arguments),this.checkpoints=new Checkpoints(this._client)}create(e,t){return this._client.post(`/fine_tuning/jobs`,{body:e,...t,__security:{bearerAuth:!0}})}retrieve(e,t){return this._client.get(path`/fine_tuning/jobs/${e}`,{...t,__security:{bearerAuth:!0}})}list(t={},n){return this._client.getAPIList(`/fine_tuning/jobs`,CursorPage,{query:t,...n,__security:{bearerAuth:!0}})}cancel(e,t){return this._client.post(path`/fine_tuning/jobs/${e}/cancel`,{...t,__security:{bearerAuth:!0}})}listEvents(t,r={},i){return this._client.getAPIList(path`/fine_tuning/jobs/${t}/events`,CursorPage,{query:r,...i,__security:{bearerAuth:!0}})}pause(e,t){return this._client.post(path`/fine_tuning/jobs/${e}/pause`,{...t,__security:{bearerAuth:!0}})}resume(e,t){return this._client.post(path`/fine_tuning/jobs/${e}/resume`,{...t,__security:{bearerAuth:!0}})}};Jobs.Checkpoints=Checkpoints;export{Jobs};